all_tasks = []
file_labels = ["Task List 1", "Task List 2", "Task List 3"]

for fpath, flabel in zip(files, file_labels):
    wb = openpyxl.load_workbook(fpath, data_only=True)
    ws = wb.active
    rows = list(ws.iter_rows(values_only=True))
    if not rows:
        continue
    header = [str(c).strip() if c else "" for c in rows[0]]
    # normalize column names
    header = [h.replace("'"\\n\", \" \").strip() for h in header]
    for row in rows[1:]:
        if row[0] is None:
            continue
        task = {}
        for i, val in enumerate(row):
            col_name = header[i] if i < len(header) else f\"col_{i}\"
            task[col_name] = val
        task[\"_source_file\"] = flabel
        all_tasks.append(task)
    wb.close()

print(f\"Total tasks loaded: {len(all_tasks)}\")

