    rec[\"assignee\"]      = get_field(t, \"Assignee\")
    rec[\"duration_days\"] = get_field(t, \"Estimated Duration (Days)\")
    rec[\"progress\"]      = get_field(t, \"Current Progress (%)\")
    rec[\"func_req\"]      = get_field(t, \"Functional Requirements (Items)\", \"Number of Functional Requirements\")
    rec[\"tech_req\"]      = get_field(t, \"Technical Requirements (Items)\", \"Number of Technical Requirements\")
    rec[\"perf_target\"]   = get_field(t, \"Performance Target (Optimization %)\", \"Performance Target Optimization Rate (%)\")
    rec[\"tech_stack\"]    = get_field(t, \"Tech Stack\")
    rec[\"complexity\"]     = get_field(t, \"Complexity\")
    rec[\"design_review\"] = get_field(t, \"Design Review\", \"Design Review Date\")
    rec[\"dev_start\"]     = get_field(t, \"Development Start\", \"Development Start Date\")
    rec[\"dev_end\"]       = get_field(t, \"Development Completion\", \"Development Completion Date\")
    rec[\"test_delivery\"]  = get_field(t, \"Testing Delivery\", \"Testing Delivery Date\")
    rec[\"issues\"]        = get_field(t, \"Issues\")
    rec[\"risk_rating\"]   = get_field(t, \"Risk Rating\")
    rec[\"description\"]   = get_field(t, \"Task Description\", \"Description\")
    rec[\"source_file\"]   = t.get(\"_source_file\", \"\")
    rec[\"code_coverage\"] = get_field(t, \"Required Code Test Coverage\")
    rec[\"other_criteria\"] = get_field(t, \"Other Completion Criteria\")
    # Ensure numeric fields are numeric
    for nf in [\"duration_days\", \"progress\", \"func_req\", \"tech_req\", \"perf_target\"]:
        try:
            rec[nf] = float(rec[nf]) if rec[nf] is not None else 0
        except (ValueError, TypeError):
            rec[nf] = 0
    unified.append(rec)

print(f\"Unified tasks: {len(unified)}\")

