// === Assignee Progress Bars ===
function renderAssigneeProgress() {
  const stats = {};
  tasks.forEach(t => {
    const a = t['Assignee'] || 'Unknown';
    if ("'!stats[a]) stats[a] = { total: 0, count: 0 };
    stats[a].total += parseFloat(t['"'Current Progress (%)'] || 0);
    stats[a].count++;
