  const sorted = Object.entries(stats).sort((a, b) => (b[1].total / b[1].count) - (a[1].total / a[1].count));
  const container = document.getElementById('assigneeProgress');
  container.innerHTML = sorted.map(([name, s]) => {
    const avg = Math.round(s.total / s.count);
    const color = avg >= 75 ? '#22c55e' : avg >= 50 ? '#eab308' : avg >= 25 ? '#f97316' : '#ef4444';
