        ${p}%
      </td>
      <td>${htmlEscape(t['"'Complexity'] || '')}</td>
      <td class=\""'${riskClass}">${htmlEscape(t['"'Risk Rating'] || '')}</td>
      <td>"'${htmlEscape(t['"'Tech Stack'] || '')}</td>
      <td style=\"text-align:center\">"'${t['"'Functional Requirements (Items)'] || ''}</td>
      <td style=\"text-align:center\">"'${t['"'Technical Requirements (Items)'] || ''}</td>
